class MinStack {
public:
    MinStack() {

    }

    void push(int val) {
        stack.push(val);
        if (minStack.empty() || val <= minStack.top()) {
            minStack.push(val);
        }
    }

    void pop() {
        if (!stack.empty()) {
            if (stack.top() == minStack.top()) {
                minStack.pop();
            }
            stack.pop();
        }
    }

    int top() {
        return stack.top();
    }

    int getMin() {
        return minStack.top();
    }
private:
    stack<int> stack;
    stack<int> minStack;
};
